const e=JSON.parse('{"key":"v-0fdd9b7f","path":"/webpack/webpack%E9%AB%98%E7%BA%A7%E9%85%8D%E7%BD%AE.html","title":"webpack高级配置","lang":"zh-CN","frontmatter":{"title":"webpack高级配置","isTimeLine":true,"date":"2023-07-17T00:00:00.000Z","category":["前端"],"tag":["JavaScript","webpack"]},"headers":[{"level":3,"title":"提升打包构建速度-HMR/Cache/Thread","slug":"提升打包构建速度-hmr-cache-thread","link":"#提升打包构建速度-hmr-cache-thread","children":[]},{"level":3,"title":"减少代码体积-Babel/图片压缩/code split","slug":"减少代码体积-babel-图片压缩-code-split","link":"#减少代码体积-babel-图片压缩-code-split","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773238261000,"updatedTime":1773238261000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":5.07,"words":1521},"filePathRelative":"webpack/webpack高级配置.md","localizedDate":"2023年7月17日","excerpt":"<h3> 提升打包构建速度-HMR/Cache/Thread</h3>\\n<h4> Cache</h4>\\n<ol>\\n<li>Cache是什么？每次打包文件都要经过<code>Eslint Bebal</code>处理，速度比较慢；可以缓存之前的Eslint检查的结果和Babel编译的结果，这样第二次打包速度就比较快。</li>\\n<li>babel: 开启babel编译缓存<code>{test: /.js$/, loader: \\"babel-loader\\", option:{cacheDirectory: true, }}</code></li>\\n<li>Eslint: cache开启缓存,cacheLocation缓存目录。<code>new ESLintWebpackPlugin({ context: path.resolve(__dirname, \\"../src\\"), exclude: \\"node_modules\\", cache: true, cacheLocation: path.resolve( __dirname,\\"../node_modules/.cache/.eslintcache\\")}) </code></li>\\n</ol>"}');export{e as data};
